// KEY-VALUE STORE OPERATIONS

// SET - Store a value with key
SET user:1001:name "John Doe"
SET user:1001:email "john@example.com"
SET user:1001:age "25"

// GET - Retrieve value by key
GET user:1001:name // Returns "John Doe"

// Complex data as value
SET session:abc123 '{"user_id": 1001, "cart": ["item1", "item2"]}'

// Hash operations (for structured data)
HSET user:1002 name "Jane" email "jane@example.com"
HGETALL user:1002

// TTL (Time To Live) - useful for caching
SET cache:popular-products ' [...] ' EX 3600

// INCREMENT - atomic counter
SET counter:views 0
INCR counter:views

// COLUMN-FAMILY STORE (CASSANDRA)

// Create keyspace
CREATE KEYSPACE IF NOT EXISTS social_app
WITH REPLICATION = {'class': 'SimpleStrategy', 'replication_factor': 3};

// Create column family (table)
CREATE TABLE IF NOT EXISTS social_app.users (
 user_id uuid PRIMARY KEY,
 username text,
 email text,
 created_at timestamp,
 // Dynamic columns can be added
);

// Create column family for user posts (wide row)
CREATE TABLE IF NOT EXISTS social_app.user_posts (
 user_id uuid,
 post_id timeuuid,
 content text,
 timestamp timestamp,
 PRIMARY KEY (user_id, post_id)
) WITH CLUSTERING ORDER BY (post_id DESC);

// Insert data
INSERT INTO social_app.users (user_id, username, email, created_at)
VALUES (uuid(), 'john_doe', 'john@example.com', now());

// Query posts by user (efficient range query)
SELECT * FROM social_app.user_posts
WHERE user_id = ?
LIMIT 10;
